const d = $input.first().json;
const exec = d.executive_summary;
const projects = (d.projects || []).map(p => `  ${p.health} ${p.name}: ${p.schedule_variance_days}d variance, ${p.open_risks} risks`).join('
');
const inbox = d.inbox;
const missions = d.missions;
const top3 = (missions.upcoming || []).slice(0,3).map(m => `  [${m.priority}] ${m.title} → ${m.assigned_to}`).join('
') || '  None queued';
const connectors = (d.connectors || []).map(c => `  ${c.connector}: ${c.errors > 0 ? c.errors + ' errors' : 'OK'} — last sync ${c.last_sync || 'never'}`).join('
') || '  None';

const body = `HCI AI — Weekly Summary
${d.period}

` +
  `WEEK PERFORMANCE
` +
  `  Hours saved: ${exec.hours_saved_this_week}h
` +
  `  Documents processed: ${exec.documents_processed}
` +
  `  Risks detected: ${exec.risks_detected}
` +
  `  Workflow runs: ${exec.workflow_runs}

` +
  `PROJECTS
${projects}

` +
  `INBOX
` +
  `  Resolved this week: ${inbox.resolved_this_week}
` +
  `  Still pending: ${inbox.still_pending}
` +
  (inbox.deferred_items.length > 0 ? `  Deferred:
${inbox.deferred_items.map(i => '    - ' + i.title).join('
')}

` : '
') +
  `MISSIONS
` +
  `  Completion rate: ${missions.complete_rate_pct}%
` +
  `  Next week:
${top3}

` +
  `CONNECTORS
${connectors}

` +
  `Dashboard: http://localhost:8000/executive`;

return [{ json: { subject: `HCI AI Weekly — ${d.report_date}`, body } }];
